CREATE OR REPLACE FUNCTION increment_gps_track_version()
RETURNS TRIGGER AS $$
BEGIN
    IF TG_OP = 'INSERT' THEN
        NEW.version = 0;
    ELSE
        NEW.version = COALESCE(OLD.version, 0) + 1;
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_gps_track_version
BEFORE INSERT OR UPDATE ON gps_track
FOR EACH ROW EXECUTE FUNCTION increment_gps_track_version();
